public class LoopConcatenation {
    public static void main(String[] args) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 1000; i++) {
            sb.append(i).append(" ");
        }
        String res = sb.toString();
        System.out.println(res);
    }
}
